query:
UPDATE leads SET 
  faixaRenda = 'Acima de 8.000,00',
  prefereContatoPor = 'WhatsApp',
  finalidadeImovel = 'Investimento'
WHERE id IN (
  SELECT id FROM (
    SELECT id FROM leads ORDER BY createdAt DESC LIMIT 5
  ) AS temp
);

